//! DEBUG: dump LTX-Video DiT block-0 forward output on a fixed deterministic
//! input for numeric cross-check against diffusers LTXVideoTransformerBlock.
//! Emits a flat little-endian f32 binary + JSON manifest of offsets.
//!
//! usage: ltx-block0-dump <knot> <out-prefix> [F] [H] [W] [cap_len]
//!   defaults: F=2 H=2 W=2 cap_len=3  (img_len = F*H*W = 8 tokens)

use std::io::Write;

use distributed_inference::loader::KnotWeights;
use distributed_inference::model_ltx_dit::debug_block0_forward;

fn stats(v: &[f32]) -> (f32, f32, f32, f32) {
    let n = v.len() as f32;
    let mean = v.iter().sum::<f32>() / n;
    let var = v.iter().map(|x| (x - mean) * (x - mean)).sum::<f32>() / n;
    let mn = v.iter().cloned().fold(f32::INFINITY, f32::min);
    let mx = v.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    (mean, var.sqrt(), mn, mx)
}

fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 3 {
        eprintln!("usage: ltx-block0-dump <knot> <out-prefix> [F] [H] [W] [cap_len]");
        std::process::exit(2);
    }
    let knot_path = &args[1];
    let out_prefix = &args[2];
    let f: usize = args.get(3).and_then(|s| s.parse().ok()).unwrap_or(2);
    let h: usize = args.get(4).and_then(|s| s.parse().ok()).unwrap_or(2);
    let w: usize = args.get(5).and_then(|s| s.parse().ok()).unwrap_or(2);
    let cap_len: usize = args.get(6).and_then(|s| s.parse().ok()).unwrap_or(3);

    let knot = KnotWeights::load_metadata_only(knot_path).expect("load knot metadata");
    let out = debug_block0_forward(knot_path, &knot, f, h, w, cap_len).expect("ltx block0 forward");

    let fields: Vec<(&str, &Vec<f32>)> = vec![("block_out", &out.block_out)];

    let bin_path = format!("{out_prefix}.bin");
    let json_path = format!("{out_prefix}.json");
    let mut file = std::fs::File::create(&bin_path).expect("create bin");
    let mut manifest = String::new();
    manifest.push_str(&format!(
        "{{\n  \"h\": {}, \"img_len\": {}, \"cap_len\": {},\n  \"fields\": {{\n",
        out.h, out.img_len, out.cap_len
    ));
    let mut offset = 0usize;
    for (i, (name, v)) in fields.iter().enumerate() {
        for x in v.iter() {
            file.write_all(&x.to_le_bytes()).unwrap();
        }
        let (mean, std, mn, mx) = stats(v);
        eprintln!(
            "{:>12} len={:>7} mean={:+.5} std={:.5} min={:+.4} max={:+.4}",
            name,
            v.len(),
            mean,
            std,
            mn,
            mx
        );
        let comma = if i + 1 == fields.len() { "" } else { "," };
        manifest.push_str(&format!(
            "    \"{}\": {{\"offset\": {}, \"len\": {}}}{}\n",
            name,
            offset,
            v.len(),
            comma
        ));
        offset += v.len();
    }
    manifest.push_str("  }\n}\n");
    std::fs::write(&json_path, manifest).expect("write json");
    eprintln!("wrote {bin_path} ({offset} f32) + {json_path}");
}
